function user_file_upload_init() {
    add_action('wp_enqueue_scripts', 'user_file_upload_enqueue_scripts');
}
add_action('init', 'user_file_upload_init');

function user_file_upload_enqueue_scripts() {
    wp_enqueue_script('user-file-upload-script', plugins_url('/js/user-file-upload.js', __FILE__), array('jquery'), null, true);
}

function user_file_upload_shortcode() {
    ob_start();
    ?>
    <div id="user-file-upload">
        <h2>Upload Profile Picture or Document</h2>
        <form id="upload-form" method="post" enctype="multipart/form-data">
            <input type="file" name="user_file" id="user_file" accept=".jpg,.jpeg,.png,.pdf,.doc,.docx">
            <button type="submit">Upload</button>
        </form>
        <div id="upload-response"></div>
    </div>
    <?php
    return ob_get_clean();
}
add_shortcode('user-file-upload', 'user_file_upload_shortcode');

function user_file_upload_process() {
    if (isset($_FILES['user_file'])) {
        $file = $_FILES['user_file'];
        $allowed_types = array('jpg', 'jpeg', 'png', 'pdf', 'doc', 'docx');
        $file_type = pathinfo($file['name'], PATHINFO_EXTENSION);
        
        if (in_array($file_type, $allowed_types)) {
            $upload_dir = wp_upload_dir();
            $target_path = $upload_dir['path'] . '/' . basename($file['name']);
            
            if (move_uploaded_file($file['tmp_name'], $target_path)) {
                echo json_encode(array('success' => true, 'message' => 'File uploaded successfully.'));
            } else {
                echo json_encode(array('success' => false, 'message' => 'Error uploading file.'));
            }
        } else {
            echo json_encode(array('success' => false, 'message' => 'Invalid file type. Allowed types: jpg, jpeg, png, pdf, doc, docx.'));
        }
    } else {
        echo json_encode(array('success' => false, 'message' => 'No file uploaded.'));
    }

    wp_die();
}
add_action('wp_ajax_user_file_upload', 'user_file_upload_process');
add_action('wp_ajax_nopriv_user_file_upload', 'user_file_upload_process');

?>